// Both ensures conjuncts force `postN_packets@.map_values(|p: CPacket| p@).to_set()`
// to equal the *same* RHS expression. Re-state this as an explicit implication so
// that z3 instantiates the (otherwise disjoint-triggered) forall quantifiers buried
// inside `un_acked_messages_for_dest` and `to_set` against a shared common term,
// and concludes the desired set equality between `post1_packets@` and `post2_packets@`
// by pure transitivity.
assert(
    ((post1_packets@.map_values(|p: CPacket| p@).to_set() ==
        pre_packets@.map_values(|p: CPacket| p@).to_set() + self_@.un_acked_messages_for_dest(src@, dst@))
    && (post2_packets@.map_values(|p: CPacket| p@).to_set() ==
        pre_packets@.map_values(|p: CPacket| p@).to_set() + self_@.un_acked_messages_for_dest(src@, dst@)))
    ==>
    (post1_packets@.map_values(|p: CPacket| p@).to_set() ==
        post2_packets@.map_values(|p: CPacket| p@).to_set())
);
